background.js.content:
function applyIframeRules() {
    chrome.declarativeNetRequest.updateDynamicRules({
        removeRuleIds: [1],
        addRules: [
            {
                id: 1,
                priority: 1,
                action: {
                    type: "modifyHeaders",
                    responseHeaders: [
                        { header: "content-security-policy", operation: "remove" },
                        { header: "x-frame-options", operation: "remove" },
                        { header: "frame-options", operation: "remove" },
                        { header: "frame-ancestors", operation: "remove" },
                        { header: "X-Content-Type-Options", operation: "remove" },
                        {
                            header: "access-control-allow-origin",
                            operation: "set",
                            value: "*"
                        }
                    ]
                },
                condition: {
                    urlFilter: "||deepseek.com",
                    resourceTypes: ["main_frame", "sub_frame"]
                }
            }
        ]
    });
}

function initiate() {
    chrome.sidePanel
        .setPanelBehavior({ openPanelOnActionClick: true })
        .catch((error) => console.error("Error setting side panel behavior:", error));

    applyIframeRules();

    chrome.runtime.onInstalled.addListener((details) => {
        applyIframeRules();

        if (details.reason === "install") {
            chrome.tabs.create({
                url: "https://chat.deepseek.com/"
            });
        }
    });

    chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
        if (request.type === "DEEPSEEK_PAGE_STATE") {
            const pageContext = request.pageContext || "unknown";
            chrome.storage.local.set(
                {
                    [`deepseekPageState:${pageContext}`]: request.state
                },
                () => {
                    chrome.runtime.sendMessage(
                        {
                            type: "DEEPSEEK_PAGE_STATE",
                            state: request.state,
                            pageContext
                        },
                        () => {
                            void chrome.runtime.lastError;
                        }
                    );

                    sendResponse({ success: true });
                }
            );
            return true;
        }

        if (request.action === "updateShortcut") {
            chrome.commands.update(
                {
                    name: "_execute_action",
                    shortcut: request.shortcut
                },
                () => {
                    if (chrome.runtime.lastError) {
                        sendResponse({
                            success: false,
                            error: chrome.runtime.lastError.message
                        });
                    } else {
                        sendResponse({ success: true });
                    }
                }
            );
            return true;
        }

        if (request.action === "getShortcut") {
            chrome.commands.getAll((commands) => {
                const command = commands.find((item) => item.name === "_execute_action");
                sendResponse({ shortcut: command ? command.shortcut : "Alt+D" });
            });
            return true;
        }

        return false;
    });

    chrome.runtime.setUninstallURL("https://forms.gle/HtAMmbJRYxfekfqd9");
}

initiate();

injectDeepSeek.js.content:
if (!window.__deepseekExtensionInjected) {
    window.__deepseekExtensionInjected = true;

    const pageContext = window.top === window ? "top-level" : "embedded";
    const AUTH_TEXT_PATTERNS = [
        /log in to deepseek/i,
        /sign in to deepseek/i,
        /enter your email/i,
        /enter your password/i,
        /continue with google/i,
        /continue with github/i,
        /forgot password/i,
        /forget password/i,
        /\bdon't have an account\?\s*sign up\b/i
    ];
    const READY_SELECTORS = [
        "#chat-input",
        "textarea",
        '[contenteditable="true"][role="textbox"]',
        'div[contenteditable="true"]',
        '[data-testid="chat-input"]',
        '[contenteditable="true"]'
    ];

    let lastPageState = null;
    let lastParentFrameState = null;
    let syncScheduled = false;

    function canUseRuntimeMessaging() {
        return typeof chrome !== "undefined" &&
            Boolean(chrome.runtime?.id) &&
            typeof chrome.runtime.sendMessage === "function";
    }

    function isVisible(element) {
        if (!(element instanceof HTMLElement)) {
            return false;
        }

        const rect = element.getBoundingClientRect();
        return rect.width > 0 && rect.height > 0;
    }

    function hasVisibleActionLabel(label) {
        const pattern = new RegExp(`^\\s*${label}\\s*$`, "i");
        return Array.from(document.querySelectorAll("button, a, [role='button']"))
            .some((element) => isVisible(element) && pattern.test(element.textContent || ""));
    }

    function isAuthPage() {
        const pathname = window.location.pathname || "";
        const bodyText = document.body?.innerText || "";
        const hasLoginCta =
            hasVisibleActionLabel("Log in") ||
            hasVisibleActionLabel("Login") ||
            hasVisibleActionLabel("Sign up") ||
            hasVisibleActionLabel("Sign in");
        const hasPasswordField = Boolean(document.querySelector('input[type="password"]'));
        const hasEmailField = Boolean(
            document.querySelector('input[type="email"]') ||
            document.querySelector('input[placeholder*="Email" i]') ||
            document.querySelector('input[placeholder*="Mail" i]')
        );
        const hasSocialAuthButton = Array
            .from(document.querySelectorAll("button, a, [role='button']"))
            .some((element) => {
                if (!(element instanceof HTMLElement)) {
                    return false;
                }
                const text = element.textContent || "";
                return /continue with google|continue with github/i.test(text);
            });
        const matchedPatterns = AUTH_TEXT_PATTERNS.filter((pattern) => pattern.test(bodyText)).length;

        if (pathname === "/auth" || pathname.startsWith("/auth/") || pathname === "/login") {
            return true;
        }

        if (hasPasswordField && (hasEmailField || hasSocialAuthButton || matchedPatterns >= 1)) {
            return true;
        }

        if (matchedPatterns >= 2) {
            return true;
        }

        return hasLoginCta;
    }

    function findChatInputElement() {
        for (const selector of READY_SELECTORS) {
            const elements = Array.from(document.querySelectorAll(selector));
            const visibleElement = elements.find((element) => isVisible(element));
            if (visibleElement) {
                return visibleElement;
            }
        }
        return null;
    }

    function detectPageState() {
        if (isAuthPage()) {
            return "auth-required";
        }

        if (findChatInputElement()) {
            return "ready";
        }

        return "loading";
    }

    function notifyPageState(state) {
        if (!canUseRuntimeMessaging() || state === lastPageState) {
            return;
        }

        lastPageState = state;

        chrome.runtime.sendMessage(
            {
                type: "DEEPSEEK_PAGE_STATE",
                state,
                pageContext
            },
            () => {
                void chrome.runtime.lastError;
            }
        );
    }

    function notifyParentFrameState(state) {
        if (window.parent === window || state === lastParentFrameState) {
            return;
        }

        lastParentFrameState = state;

        window.parent.postMessage(
            {
                type: "DEEPSEEK_EMBEDDED_PAGE_STATE",
                state
            },
            "*"
        );
    }

    function syncPageState() {
        const state = detectPageState();
        notifyPageState(state);
        notifyParentFrameState(state);
    }

    function schedulePageStateSync() {
        if (syncScheduled) {
            return;
        }

        syncScheduled = true;
        window.requestAnimationFrame(() => {
            syncScheduled = false;
            syncPageState();
        });
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", schedulePageStateSync, { once: true });
    } else {
        schedulePageStateSync();
    }

    window.addEventListener("message", (event) => {
        if (!event.data || typeof event.data !== "object") {
            return;
        }

        if (event.data.type !== "DEEPSEEK_REQUEST_PAGE_STATE") {
            return;
        }

        syncPageState();
    });

    const observer = new MutationObserver(() => {
        schedulePageStateSync();
    });

    if (document.documentElement) {
        observer.observe(document.documentElement, { childList: true, subtree: true });
    }
}

